import { useEffect, useState } from "react";
import schoolsDepartments from "../../data/schoolsDepartments";
import { useAuth } from "../../context/AuthContext";

import DeanLayout from "../../layouts/DeanLayout";

import {

  getFacultySubmissions,

  downloadFacultyPDF

} from "../../api/deanApi";

function DeanFacultyReview() {

    const { user } = useAuth();
    const [selectedDepartment, setSelectedDepartment] =
  useState("");
  
  const [submissions, setSubmissions] =
    useState([]);

  const [loading, setLoading] =
    useState(true);

  useEffect(() => {

    loadFacultySubmissions();

  }, []);

  const loadFacultySubmissions =
    async () => {

      try {

        const res =
          await getFacultySubmissions();

        setSubmissions(

          res.data.submissions || []

        );

      }

      catch (err) {

        console.error(err);

      }

      finally {

        setLoading(false);

      }

    };

  // ==========================
  // PDF DOWNLOAD
  // ==========================

  const handleDownload =
    async (submission) => {

      try {

        const response =
          await downloadFacultyPDF(
            submission._id
          );

        const url =
          window.URL.createObjectURL(
            new Blob([response.data])
          );

        const link =
          document.createElement("a");

        link.href = url;

        link.download =
          `${submission.submittedByName}_${submission.quarter}.pdf`;

        document.body.appendChild(link);

        link.click();

        link.remove();

      }

      catch (error) {

        console.error(error);

      }

    };

  // ==========================
  // GROUP BY DEPARTMENT
  // ==========================

  const groupedDepartments =
    submissions.reduce(

      (acc, submission) => {

        const dept =
          submission.department;

        if (!acc[dept]) {

          acc[dept] = [];

        }

        acc[dept].push(submission);

        return acc;

      },

      {}

    );
    // ==========================
// DEPARTMENTS OF DEAN SCHOOL
// ==========================

const departments =

  schoolsDepartments[user?.school] || [];

// ==========================
// FILTERED SUBMISSIONS
// ==========================

const filteredSubmissions =

  selectedDepartment

    ?

    submissions.filter(

      (submission) =>

        submission.department ===

        selectedDepartment

    )

    :

    [];

  return (

    <DeanLayout>

      <div
  style={{
    padding: "30px"
  }}
>

  <h1
    style={{
      marginBottom: "10px"
    }}
  >
    Faculty Reviews
  </h1>
 <div
  style={{
    marginBottom: "30px"
  }}
>

  <label
    style={{
      fontWeight: "600",
      display: "block",
      marginBottom: "10px"
    }}
  >

    Select Department

  </label>

  <select

    value={selectedDepartment}

    onChange={(e) =>

      setSelectedDepartment(

        e.target.value

      )

    }

    style={{

      width: "420px",

      padding: "12px",

      borderRadius: "8px",

      border: "1px solid #d1d5db"

    }}

  >

    <option value="">

      -- Select Department --

    </option>

    {

      departments.map(

        (department) => (

          <option

            key={department}

            value={department}

          >

            {department}

          </option>

        )

      )

    }

  </select>

</div>
  <p
    style={{
      color: "#6b7280",
      marginBottom: "30px"
    }}
  >
    Department-wise Faculty Submissions
    Approved by HOD
  </p>

  {

    Object.keys(groupedDepartments)

      .sort()

      .map((department) => (

        <div
          key={department}
          style={{
            marginBottom: "35px",
            background: "#fff",
            borderRadius: "12px",
            boxShadow:
              "0 2px 8px rgba(0,0,0,.08)",
            overflow: "hidden"
          }}
        >

          <div
            style={{
              background: "#2563eb",
              color: "#fff",
              padding: "15px 20px",
              fontWeight: "bold",
              fontSize: "18px"
            }}
          >

            {department}

          </div>

          {

            groupedDepartments[
              department
            ].length === 0

            ?

            <div
              style={{
                padding: "25px",
                textAlign: "center",
                color: "#dc2626",
                fontWeight: "600"
              }}
            >

              NO FACULTY APPROVED BY HOD

            </div>

            :

            <table
              style={{
                width: "100%",
                borderCollapse: "collapse"
              }}
            >

              <thead>

                <tr
                  style={{
                    background: "#eff6ff"
                  }}
                >

                  <th style={thStyle}>
                    Faculty
                  </th>

                  <th style={thStyle}>
                    Email
                  </th>

                  <th style={thStyle}>
                    Department
                  </th>

                  <th style={thStyle}>
                    Quarter
                  </th>

                  <th style={thStyle}>
                    Answered
                  </th>

                  <th style={thStyle}>
                    Submitted Date
                  </th>

                  <th style={thStyle}>
                    Actions
                  </th>

                </tr>

              </thead>

              <tbody>

                {

                  groupedDepartments[
                    department
                  ].map(

                    (submission) => (

                      <tr
                        key={submission._id}
                      >

                        <td style={tdStyle}>

                          {

                            submission.submittedByName

                          }

                        </td>

                        <td style={tdStyle}>

                          {

                            submission.submittedByEmail

                          }

                        </td>

                        <td style={tdStyle}>

                          {

                            submission.department

                          }

                        </td>

                        <td style={tdStyle}>

                          {

                            submission.quarter

                          }

                        </td>

                        <td style={tdStyle}>

                          {

                            submission.answeredCount

                          }

                          /

                          {

                            submission.totalQuestions

                          }

                        </td>

                        <td style={tdStyle}>

                          {

                            new Date(

                              submission.createdAt

                            ).toLocaleDateString()

                          }

                        </td>

                        <td style={tdStyle}>

                          {/* PART 4 */}

                        </td>

                      </tr>

                    )

                  )

                }

              </tbody>

            </table>

          }

        </div>

      ))

  }

</div>
    </DeanLayout>

  );

}
const thStyle = {

  padding: "12px",

  textAlign: "left",

  background: "#dbeafe"

};

const tdStyle = {

  padding: "12px",

  borderBottom:
    "1px solid #e5e7eb"

};
export default DeanFacultyReview;
